from scipy.spatial import ConvexHull

def calculate_convex_hull(points):
    # Check if all points are 4D
    if not all(len(point) == 4 for point in points):
        raise ValueError("All points must be 4D")

    # Check for degenerate cases
    if len(points) == 1:
        return np.array(points)
    elif len(points) == 2:
        return np.array(points)
    elif len(points) == 3:
        # Check if points are coplanar
        v1 = np.array(points[1]) - np.array(points[0])
        v2 = np.array(points[2]) - np.array(points[0])
        cross_product = np.cross(v1, v2)
        if np.all(cross_product == 0):
            return np.array(points)
    elif len(points) == 4:
        # Check if points are coplanar
        v1 = np.array(points[1]) - np.array(points[0])
        v2 = np.array(points[2]) - np.array(points[0])
        v3 = np.array(points[3]) - np.array(points[0])
        cross_product = np.cross(v1, v2)
        dot_product = np.dot(cross_product, v3)
        if dot_product == 0:
            return np.array(points)

    # Calculate convex hull using Qhull algorithm
    hull = ConvexHull(points)
    return hull.points[hull.vertices]

