class Point:
    def __init__(self, coordinates):
        if len(coordinates) != 4:
            raise ValueError("Point must have 4 dimensions")
        self.coordinates = coordinates

class ConvexHull:
    def __init__(self, points):
        self.points = [Point(point) for point in points]
        self.hull = self.calculate_convex_hull()

    def orientation(self, p, q, r):
        val = (q.coordinates[1] - p.coordinates[1]) * (r.coordinates[0] - q.coordinates[0]) - (q.coordinates[0] - p.coordinates[0]) * (r.coordinates[1] - q.coordinates[1])
        if val == 0:
            return 0  # Collinear
        elif val > 0:
            return 1  # Clockwise
        else:
            return 2  # Counterclockwise

    def convex_hull_2d(self, points):
        n = len(points)
        if n < 3:
            raise ValueError("Convex hull not possible")

        hull = []
        l = 0
        for i in range(1, n):
            if points[i].coordinates[0] < points[l].coordinates[0]:
                l = i

        p = l
        q = 0
        while True:
            hull.append(points[p])
            q = (p + 1) % n

            for i in range(n):
                if self.orientation(points[p], points[i], points[q]) == 2:
                    q = i

            p = q
            if p == l:
                break

        return hull

    def calculate_convex_hull(self):
        if len(self.points) < 4:
            return self.points

        hull = []
        for i in range(len(self.points)):
            plane = []
            for j in range(len(self.points)):
                if i != j:
                    plane.append(self.project_point(self.points[j], self.points[i]))

            plane_hull = self.convex_hull_2d(plane)
            for point in plane_hull:
                hull.append(self.reconstruct_point(point, self.points[i]))

        return hull

    def project_point(self, point, reference):
        vector = [point.coordinates[i] - reference.coordinates[i] for i in range(4)]
        normal = [0, 0, 0, 0]
        normal[0] = vector[1] * vector[3] - vector[2] * vector[2]
        normal[1] = vector[2] * vector[3] - vector[0] * vector[2]
        normal[2] = vector[0] * vector[1] - vector[3] * vector[0]
        normal[3] = vector[0] * vector[2] - vector[1] * vector[1]

        magnitude = sum([x * x for x in normal]) ** 0.5
        normal = [x / magnitude for x in normal]

        projected = [reference.coordinates[i] + vector[i] - (sum([vector[j] * normal[j] for j in range(4)])) * normal[i] for i in range(4)]

        return Point(projected[:2])

    def reconstruct_point(self, point, reference):
        normal = [0, 0, 0, 0]
        normal[0] = point.coordinates[1] * point.coordinates[1] - point.coordinates[0] * point.coordinates[0]
        normal[1] = point.coordinates[0] * point.coordinates[0] - point.coordinates[1] * point.coordinates[1]
        normal[2] = point.coordinates[0] * point.coordinates[1]
        normal[3] = point.coordinates[0] * point.coordinates[1]

        magnitude = sum([x * x for x in normal]) ** 0.5
        normal = [x / magnitude for x in normal]

        vector = [point.coordinates[i] - reference.coordinates[i] for i in range(2)]

        point_4d = [reference.coordinates[i] + vector[0] * normal[0] + vector[1] * normal[1] for i in range(4)]

        return Point(point_4d)

    def get_convex_hull(self):
        return self.hull

